const content = $input.first().json.choices[0].message.content;

// Limpiar caracteres problemáticos
const cleaned = content
  .replace(/```json/g, '')
  .replace(/```/g, '')
  .replace(/[\x00-\x1F\x7F]/g, ' ')
  .trim();

// Buscar el JSON dentro del texto
const jsonMatch = cleaned.match(/\{[\s\S]*\}/);

if (jsonMatch) {
  try {
    const parsed = JSON.parse(jsonMatch[0]);
    return [{ json: parsed }];
  } catch(e) {
    return [{ json: {
      sentimiento: "Negativo",
      categoria: "Urgente",
      urgencia: "Alta",
      score_negativo: 80,
      resumen: "Error al parsear respuesta",
      respuesta_draft: content
    }}];
  }
} else {
  return [{ json: {
    sentimiento: "Negativo",
    categoria: "Urgente", 
    urgencia: "Alta",
    score_negativo: 80,
    resumen: "No se encontro JSON en la respuesta",
    respuesta_draft: content
  }}];
}
